import{_ as e,o as n,c as a,ag as r}from"./chunks/framework.6MCaaFDc.js";const b=JSON.parse('{"title":"Web Evolution","description":"","frontmatter":{},"headers":[],"relativePath":"theory/internet/web-evolution.md","filePath":"theory/internet/web-evolution.md"}'),i={name:"theory/internet/web-evolution.md"};function s(o,t,d,l,c,h){return n(),a("div",null,[...t[0]||(t[0]=[r(`<h1 id="web-evolution" tabindex="-1">Web Evolution <a class="header-anchor" href="#web-evolution" aria-label="Permalink to &quot;Web Evolution&quot;">​</a></h1><p>The web you use today is nothing like the web of the 1990s. From static pages that only showed text to interactive platforms where you create content, to AI-driven experiences — the web has evolved through three distinct generations.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 11</p><p>Web evolution (Web 1.0, 2.0, 3.0) is primarily a Grade 11 topic. Grade 12 extends this with semantic web, scripting languages, and emerging technologies.</p></div><hr><h2 id="the-three-generations-of-the-web" tabindex="-1">The Three Generations of the Web <a class="header-anchor" href="#the-three-generations-of-the-web" aria-label="Permalink to &quot;The Three Generations of the Web&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th><strong>Web 1.0</strong></th><th><strong>Web 2.0</strong></th><th><strong>Web 3.0</strong></th></tr></thead><tbody><tr><td><strong>Era</strong></td><td>~1991–2004</td><td>~2004–present</td><td>Emerging</td></tr><tr><td><strong>Type</strong></td><td>Read-only</td><td>Read-Write</td><td>Semantic / Intelligent</td></tr><tr><td><strong>Content created by</strong></td><td>Website owners only</td><td>Users and owners</td><td>Machines and users</td></tr><tr><td><strong>User role</strong></td><td>Passive consumer</td><td>Active participant</td><td>Intelligent interaction</td></tr><tr><td><strong>Key technologies</strong></td><td>Static HTML, GIF images</td><td>AJAX, APIs, JavaScript, CSS</td><td>AI, blockchain, RDF, linked data</td></tr><tr><td><strong>Interaction</strong></td><td>None — pages are fixed</td><td>Comments, likes, sharing, uploads</td><td>Personalised, context-aware</td></tr><tr><td><strong>Examples</strong></td><td>Early news sites, brochure pages</td><td>Facebook, YouTube, Wikipedia, Twitter</td><td>AI assistants, IoT dashboards, smart search</td></tr></tbody></table><hr><h2 id="web-1-0-—-the-read-only-web" tabindex="-1">Web 1.0 — The Read-Only Web <a class="header-anchor" href="#web-1-0-—-the-read-only-web" aria-label="Permalink to &quot;Web 1.0 — The Read-Only Web&quot;">​</a></h2><p>The first generation of the web (early-to-mid 1990s through early 2000s).</p><p><strong>Characteristics:</strong></p><ul><li>Static HTML pages — content never changes unless the webmaster edits the file</li><li>No user interaction — you read but cannot contribute</li><li>No user accounts, no comments, no dynamic content</li><li>Pages linked together with hyperlinks</li><li>Limited multimedia (mostly text and images)</li><li>Dial-up internet — slow loading</li></ul><p><strong>Technology:</strong></p><ul><li>Static HTML files on web servers</li><li>Basic CSS for styling</li><li>No databases behind the pages</li></ul><p><strong>Examples:</strong></p><ul><li>Brochure-style company websites</li><li>Early news archives</li><li>Personal &quot;homepage&quot; sites</li><li>Government information pages</li></ul><hr><h2 id="web-2-0-—-the-read-write-web" tabindex="-1">Web 2.0 — The Read-Write Web <a class="header-anchor" href="#web-2-0-—-the-read-write-web" aria-label="Permalink to &quot;Web 2.0 — The Read-Write Web&quot;">​</a></h2><p>The second generation, emerging around 2004–2005 and continuing today.</p><p><strong>Characteristics:</strong></p><ul><li>Users <strong>create, share, and interact</strong> with content</li><li>User-generated content is central</li><li>Social networking, blogs, wikis, video hosting</li><li>Web applications that function like desktop software</li><li>Personalisation — your experience differs from someone else&#39;s</li></ul><p><strong>Key technologies:</strong></p><table tabindex="0"><thead><tr><th>Technology</th><th>Role</th></tr></thead><tbody><tr><td><strong>AJAX</strong></td><td>Updates parts of a page without full reload (Asynchronous JavaScript and XML)</td></tr><tr><td><strong>JavaScript</strong></td><td>Adds interactivity and dynamic behaviour to pages</td></tr><tr><td><strong>CSS frameworks</strong></td><td>Responsive design, consistent styling</td></tr><tr><td><strong>APIs</strong></td><td>Applications communicate and share data with each other</td></tr><tr><td><strong>Databases</strong></td><td>Dynamic content served from server-side databases</td></tr><tr><td><strong>Rich multimedia</strong></td><td>Embedded video, audio, interactive maps</td></tr></tbody></table><p><strong>Examples:</strong></p><ul><li><strong>Social networks</strong>: Facebook, Instagram, X (Twitter)</li><li><strong>Video platforms</strong>: YouTube, TikTok</li><li><strong>Collaborative tools</strong>: Wikipedia, Google Docs</li><li><strong>Blogging</strong>: WordPress, Blogger</li><li><strong>Shopping</strong>: Amazon (reviews, recommendations)</li><li><strong>Email as web app</strong>: Gmail (no page reload)</li></ul><p><strong>Web 2.0 risks:</strong></p><ul><li>Privacy — users share vast personal data</li><li>Misinformation — anyone can publish anything</li><li>Addiction by design — engagement algorithms</li><li>Data ownership — platform owns your content</li></ul><hr><h2 id="web-3-0-—-the-semantic-web" tabindex="-1">Web 3.0 — The Semantic Web <a class="header-anchor" href="#web-3-0-—-the-semantic-web" aria-label="Permalink to &quot;Web 3.0 — The Semantic Web&quot;">​</a></h2><p>The third generation is still emerging, with different definitions in use:</p><h3 id="semantic-web-tim-berners-lee-s-vision" tabindex="-1">Semantic Web (Tim Berners-Lee&#39;s vision) <a class="header-anchor" href="#semantic-web-tim-berners-lee-s-vision" aria-label="Permalink to &quot;Semantic Web (Tim Berners-Lee&#39;s vision)&quot;">​</a></h3><p>The web of <strong>meaningful data</strong> — machines can understand content, not just display it.</p><ul><li>Current web: pages are for humans to read</li><li>Semantic web: data tagged with meaning so machines can process it</li><li>Uses <strong>RDF</strong> (Resource Description Framework) and <strong>ontologies</strong> to describe relationships</li></ul><p><strong>Example:</strong> Instead of searching &quot;hotels near Cape Town&quot;, a semantic web agent finds available rooms, compares prices, and books for you — understanding context and meaning.</p><h3 id="web-3-0-decentralised-web" tabindex="-1">Web 3.0 / Decentralised Web <a class="header-anchor" href="#web-3-0-decentralised-web" aria-label="Permalink to &quot;Web 3.0 / Decentralised Web&quot;">​</a></h3><p>Also used to mean a <strong>decentralised web</strong> built on blockchain:</p><ul><li>No central platform controls your data</li><li>Users own their own digital identity and assets</li><li><strong>NFTs</strong>, <strong>cryptocurrency</strong>, <strong>decentralised apps (dApps)</strong></li></ul><h3 id="ai-driven-web" tabindex="-1">AI-Driven Web <a class="header-anchor" href="#ai-driven-web" aria-label="Permalink to &quot;AI-Driven Web&quot;">​</a></h3><p>Web 3.0 also describes AI-enhanced experiences:</p><ul><li>AI assistants understand natural language queries</li><li>Personalised content recommendations</li><li>Voice search and conversational interfaces</li><li>Context-aware responses</li></ul><p><strong>Examples of Web 3.0 concepts:</strong></p><ul><li>AI chat assistants (ChatGPT, Gemini)</li><li>Smart search understanding intent, not just keywords</li><li>IoT dashboards connecting physical and digital worlds</li><li>Decentralised social media platforms</li></ul><hr><h2 id="web-evolution-summary" tabindex="-1">Web Evolution Summary <a class="header-anchor" href="#web-evolution-summary" aria-label="Permalink to &quot;Web Evolution Summary&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Web 1.0: &quot;Here is information&quot; (one-way broadcast)</span></span>
<span class="line"><span>Web 2.0: &quot;Let&#39;s interact and share&quot; (two-way participation)</span></span>
<span class="line"><span>Web 3.0: &quot;I understand what you mean&quot; (intelligent interpretation)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><hr><h2 id="static-vs-dynamic-websites" tabindex="-1">Static vs Dynamic Websites <a class="header-anchor" href="#static-vs-dynamic-websites" aria-label="Permalink to &quot;Static vs Dynamic Websites&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Static Website</th><th>Dynamic Website</th></tr></thead><tbody><tr><td>Content</td><td>Fixed HTML — same for everyone</td><td>Generated per request — personalised</td></tr><tr><td>Database</td><td>No</td><td>Yes (SQL/NoSQL database)</td></tr><tr><td>User interaction</td><td>Minimal</td><td>Extensive (login, forms, transactions)</td></tr><tr><td>Languages</td><td>HTML + CSS only</td><td>HTML + CSS + PHP/Python + Database</td></tr><tr><td>Update method</td><td>Edit HTML files manually</td><td>Update database → all pages reflect change</td></tr><tr><td>Speed</td><td>Fast (no processing)</td><td>Slightly slower (server processing)</td></tr><tr><td>Cost</td><td>Low</td><td>Higher</td></tr><tr><td>Examples</td><td>Portfolio site, info page</td><td>Online banking, social media, e-commerce</td></tr></tbody></table><hr><h2 id="intranet-vs-extranet-vs-internet" tabindex="-1">Intranet vs Extranet vs Internet <a class="header-anchor" href="#intranet-vs-extranet-vs-internet" aria-label="Permalink to &quot;Intranet vs Extranet vs Internet&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th><strong>Internet</strong></th><th><strong>Intranet</strong></th><th><strong>Extranet</strong></th></tr></thead><tbody><tr><td>Access</td><td>Anyone</td><td>Internal staff only</td><td>Authorised external parties</td></tr><tr><td>Ownership</td><td>Public infrastructure</td><td>Organisation&#39;s private network</td><td>Organisation&#39;s private network</td></tr><tr><td>Content</td><td>Everything</td><td>Internal documents, tools</td><td>Specific shared resources</td></tr><tr><td>Examples</td><td>WWW</td><td>Staff portal, internal email</td><td>Supplier ordering system, patient portal</td></tr></tbody></table><hr><h2 id="emerging-web-technologies" tabindex="-1">Emerging Web Technologies <a class="header-anchor" href="#emerging-web-technologies" aria-label="Permalink to &quot;Emerging Web Technologies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Technology</th><th>Description</th></tr></thead><tbody><tr><td><strong>Progressive Web Apps (PWA)</strong></td><td>Web apps that work like native mobile apps (offline, push notifications)</td></tr><tr><td><strong>WebAssembly</strong></td><td>Near-native performance code running in the browser</td></tr><tr><td><strong>Voice search</strong></td><td>Natural language queries via voice assistants</td></tr><tr><td><strong>Augmented Reality (AR) web</strong></td><td>AR experiences in browsers (WebXR)</td></tr><tr><td><strong>AI integration</strong></td><td>AI APIs powering web services</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Web 1.0</strong></td><td>First-generation read-only web with static pages</td></tr><tr><td><strong>Web 2.0</strong></td><td>Second-generation interactive web with user-generated content</td></tr><tr><td><strong>Web 3.0</strong></td><td>Third-generation semantic/AI-driven/decentralised web</td></tr><tr><td><strong>Static website</strong></td><td>Website with fixed HTML content — same for every visitor</td></tr><tr><td><strong>Dynamic website</strong></td><td>Website that generates content from a database per request</td></tr><tr><td><strong>AJAX</strong></td><td>Technology for updating page content without full reload</td></tr><tr><td><strong>API</strong></td><td>Application Programming Interface — allows applications to communicate</td></tr><tr><td><strong>Semantic web</strong></td><td>Vision of web where data has machine-readable meaning</td></tr><tr><td><strong>Intranet</strong></td><td>Private network accessible only to internal staff</td></tr><tr><td><strong>Extranet</strong></td><td>Private network extended to authorised external users</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;What is the main difference between Web 1.0 and Web 2.0?&quot;</strong> — Web 1.0 is read-only; content created only by website owners. Web 2.0 is read-write; users create and share content (social media, YouTube, Wikipedia)</p></li><li><p><strong>&quot;Give TWO characteristics of Web 2.0&quot;</strong> — user-generated content; social networking; interactive applications; personalised experience; AJAX updates without page reload</p></li><li><p><strong>&quot;What is the semantic web (Web 3.0)?&quot;</strong> — A web where data has machine-readable meaning; machines can understand context and process information intelligently</p></li><li><p><strong>&quot;Explain the difference between a static and dynamic website&quot;</strong> — Static: fixed HTML, same for all visitors, no database; Dynamic: content generated from database per request, personalised per user</p></li><li><p><strong>&quot;What is the difference between an intranet and an extranet?&quot;</strong> — Intranet: accessible to internal employees only; Extranet: extends access to authorised external parties (suppliers, clients)</p></li></ol></div>`,59)])])}const p=e(i,[["render",s]]);export{b as __pageData,p as default};
